-- ============================================================================
CREATE INDEX idx_unidades_edificio_id ON unidades (edificio_id);

CREATE INDEX idx_usuarios_edificio_id ON usuarios (edificio_id);

CREATE INDEX idx_ordenes_trabajo_unidad_id ON ordenes_trabajo (unidad_id);
CREATE INDEX idx_ordenes_trabajo_tecnico_id ON ordenes_trabajo (tecnico_id);
CREATE INDEX idx_ordenes_trabajo_asignador_id ON ordenes_trabajo (asignador_id);
CREATE INDEX idx_ordenes_trabajo_user_carga_id ON ordenes_trabajo (user_carga_id);
CREATE INDEX idx_ordenes_trabajo_orden_revision_id ON ordenes_trabajo (orden_revision_id);
CREATE INDEX idx_ordenes_trabajo_status ON ordenes_trabajo (status);

CREATE INDEX idx_bitacoras_orden_trabajo_id ON bitacoras (orden_trabajo_id);
CREATE INDEX idx_bitacoras_usuario_id ON bitacoras (usuario_id);

CREATE INDEX idx_fotos_bitacora_orden_trabajo_id ON fotos_bitacora (orden_trabajo_id);
