CREATE INDEX idx_repuestos_ot_orden_trabajo_id ON repuestos_ot (orden_trabajo_id);
CREATE INDEX idx_repuestos_ot_articulo_id ON repuestos_ot (articulo_id);
CREATE INDEX idx_repuestos_ot_usuario_id ON repuestos_ot (usuario_id);

CREATE INDEX idx_stock_articulo_id ON stock (articulo_id);
CREATE INDEX idx_stock_usuario_id ON stock (usuario_id);

