CREATE INDEX idx_movimientos_stock_articulo_id ON movimientos_stock (articulo_id);
CREATE INDEX idx_movimientos_stock_edificio_id ON movimientos_stock (edificio_id);
CREATE INDEX idx_movimientos_stock_usuario_id ON movimientos_stock (usuario_id);
CREATE INDEX idx_movimientos_stock_fecha ON movimientos_stock (fecha);

CREATE INDEX idx_salidas_stock_articulo_id ON salidas_stock (articulo_id);
CREATE INDEX idx_salidas_stock_tecnico_id ON salidas_stock (tecnico_id);
CREATE INDEX idx_salidas_stock_usuario_id ON salidas_stock (usuario_id);

CREATE INDEX idx_compras_usuario_id ON compras (usuario_id);
CREATE INDEX idx_compras_status ON compras (status);

CREATE INDEX idx_detalle_compras_compra_id ON detalle_compras (compra_id);
CREATE INDEX idx_detalle_compras_articulo_id ON detalle_compras (articulo_id);
CREATE INDEX idx_detalle_compras_edificio_id ON detalle_compras (edificio_id);
CREATE INDEX idx_detalle_compras_usuario_id ON detalle_compras (usuario_id);

CREATE INDEX idx_aprobaciones_compra_id ON aprobaciones (compra_id);
CREATE INDEX idx_aprobaciones_user_gen_id ON aprobaciones (user_gen_id);
CREATE INDEX idx_aprobaciones_user_aprob_id ON aprobaciones (user_aprob_id);

CREATE INDEX idx_ventilaciones_unidad_id ON ventilaciones (unidad_id);
CREATE INDEX idx_ventilaciones_asignado_id ON ventilaciones (asignado_id);
CREATE INDEX idx_ventilaciones_estado ON ventilaciones (estado);

CREATE INDEX idx_documentos_orden_trabajo_id ON documentos (orden_trabajo_id);
CREATE INDEX idx_documentos_compra_id ON documentos (compra_id);

-- ============================================================================
-- RPC: finalizar_ventilacion
-- Closes a ventilacion cycle and opens the next one atomically:
--   1) marks the given row 'Realizada' (obs + closing photo + timestamp)
--   2) inserts the next cycle row: 'Pendiente', proxima_limpieza = today + frecuencia_dias
-- Both steps run inside one function call, i.e. one transaction — if either
-- statement fails the whole thing rolls back, so there's never a ventilacion
-- left "Realizada" without its successor (or vice versa).
-- ============================================================================
CREATE OR REPLACE FUNCTION finalizar_ventilacion(
  p_id bigint,
  p_obs text,
  p_foto_path text
)
RETURNS bigint
LANGUAGE plpgsql
AS $$
DECLARE
  v_unidad_id bigint;
  v_direccion_edificio text;
  v_edificio text;
  v_habitacion text;
  v_frecuencia_dias numeric;
  v_asignado_id bigint;
  v_new_id bigint;
BEGIN
  UPDATE ventilaciones
  SET
    estado = 'Realizada',
    obs_resuelto = p_obs,
    foto_path = coalesce(p_foto_path, foto_path),
    fecha_finalizacion = now()
  WHERE id = p_id
  RETURNING
    unidad_id, direccion_edificio, edificio, habitacion, frecuencia_dias, asignado_id
    INTO v_unidad_id, v_direccion_edificio, v_edificio, v_habitacion, v_frecuencia_dias, v_asignado_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'finalizar_ventilacion: ventilacion % not found', p_id;
  END IF;

  INSERT INTO ventilaciones (
    estado, unidad_id, direccion_edificio, edificio, habitacion,
    frecuencia_dias, fecha_ultima, proxima_limpieza, asignado_id
  )
  VALUES (
    'Pendiente', v_unidad_id, v_direccion_edificio, v_edificio, v_habitacion,
    v_frecuencia_dias, current_date, current_date + coalesce(v_frecuencia_dias, 0)::int, v_asignado_id
  )
  RETURNING id INTO v_new_id;

  RETURN v_new_id;
END;
$$;

COMMENT ON FUNCTION finalizar_ventilacion(bigint, text, text) IS
  'Closes a ventilacion cycle (estado=Realizada, obs + foto) and atomically '
  'inserts the next cycle (estado=Pendiente, proxima_limpieza = current_date + '
  'frecuencia_dias). Returns the new row''s id. Replaces the desktop/mobile '
  '"finalizar ventilacion" flow.';

-- ============================================================================
-- ROW LEVEL SECURITY — placeholder policies only
-- TODO: replace with real per-perfil policies once the backend/auth model is
-- decided (see data_model.md "## Auth"). For now every table is RLS-enabled
-- with a single permissive policy so `anon`/service-role access stops working
-- accidentally, while any authenticated Supabase user can read/write everything.
-- ============================================================================
DO $$
DECLARE
  t text;
BEGIN
  FOR t IN SELECT unnest(ARRAY[
    'edificios', 'articulos', 'frecuencias', 'unidades', 'usuarios',
    'perfiles_permisos', 'iconos_app', 'emails_notificacion', 'ordenes_trabajo',
    'bitacoras', 'fotos_bitacora', 'repuestos_ot', 'stock', 'stock_edificios',
    'movimientos_stock', 'salidas_stock', 'compras', 'detalle_compras',
    'aprobaciones', 'ventilaciones', 'documentos'
  ])
  LOOP
    EXECUTE format('ALTER TABLE %I ENABLE ROW LEVEL SECURITY;', t);
    EXECUTE format(
      'CREATE POLICY %I ON %I FOR ALL TO authenticated USING (true) WITH CHECK (true);',
      t || '_todo_authenticated_all', t
    );
  END LOOP;
END;
$$;
